CREATE TABLE IF NOT EXISTS `dealership_groups` (
  `id` int NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `name` varchar(255) NOT NULL,
  `slug` varchar(64) NOT NULL,
  `isActive` boolean DEFAULT true,
  `createdAt` timestamp DEFAULT NOW(),
  `updatedAt` timestamp DEFAULT NOW() ON UPDATE NOW(),
  UNIQUE KEY `dealership_groups_slug_unique` (`slug`)
);

CREATE TABLE IF NOT EXISTS `user_rooftop_assignments` (
  `id` int NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `userId` int NOT NULL,
  `dealershipId` int NOT NULL,
  `isActive` boolean DEFAULT true,
  `assignedAt` timestamp DEFAULT NOW()
);

ALTER TABLE `dealerships` ADD COLUMN IF NOT EXISTS `groupId` int DEFAULT NULL;

ALTER TABLE `users` ADD COLUMN IF NOT EXISTS `isGroupAdmin` boolean NOT NULL DEFAULT false;

ALTER TABLE `invitations` ADD COLUMN IF NOT EXISTS `groupId` int DEFAULT NULL;

